// =================================================================
// PROJECT: 5-Stage Pipeline RISC-V Processor
// FILE: RV32IM_Core.v
// DESCRIPTION: Main Top Module for Pipelined RISC-V 32-bit CPU
// =================================================================

module RV32IM_Core (
    input  wire        clk,
    input  wire        rst_n,

    // Instruction Memory Interface
    output wire [31:0] imem_addr,
    input  wire [31:0] imem_rdata,

    // Data Memory Interface
    output wire        dmem_we,
    output wire [31:0] dmem_addr,
    output wire [31:0] dmem_wdata,
    input  wire [31:0] dmem_rdata
);

    // --- PIPELINE REGISTER STAGES ---
    reg [31:0] if_pc, id_pc, ex_pc, mem_pc, wb_pc;
    reg [31:0] id_instr;

    // Decode Stage Signals
    wire [4:0]  rs1 = id_instr[19:15];
    wire [4:0]  rs2 = id_instr[24:20];
    wire [4:0]  rd  = id_instr[11:7];
    wire [6:0]  opcode = id_instr[6:0];
    wire [31:0] imm = decode_imm(id_instr);

    // Forwarding logic
    wire [1:0] forward_a, forward_b;
    wire [31:0] src_a = (forward_a == 2'b10) ? mem_alu_result :
                        (forward_a == 2'b01) ? wb_result : rf_rdata1;

    // Execution Unit (ALU + Multiplier)
    wire [31:0] alu_out;
    wire        alu_zero;

    ALU alu_inst ( 
        .a(src_a),
        .b(src_b_final),
        .ctrl(alu_ctrl),
        .out(alu_out),
        .zero(alu_zero)
    );

    // Instantiate Divider & Multiplier (M-Extension)
    wire [31:0] mult_out;
    M_Extension_Unit m_unit (
        .clk(clk),
        .rst_n(rst_n),
        .rs1_val(src_a),
        .rs2_val(src_b_final),
        .m_op(m_ctrl),
        .out(mult_out)
    );

endmodule

// =================================================================
// FILE: ALU.v
// DESCRIPTION: 32-bit Arithmetic Logic Unit with zero flag detection
// =================================================================

module ALU (
    input  wire [31:0] a,
    input  wire [31:0] b,
    input  wire [3:0]  ctrl,
    output reg  [31:0] out,
    output wire        zero
);
    assign zero = (out == 32'b0);

    always @(*) begin
        case (ctrl) 
            4'b0000: out = a + b;       // ADD
            4'b1000: out = a - b;       // SUB
            4'b0001: out = a << b[4:0]; // SLL
            4'b0010: out = ($signed(a) < $signed(b)) ? 32'b1 : 32'b0; // SLT
            4'b0100: out = a ^ b;       // XOR
            4'b0110: out = a | b;       // OR
            4'b0111: out = a & b;       // AND
            default: out = 32'b0;
        endcase
    end
endmodule

// =================================================================
// PROJECT: 5-Stage SoC with Custom RISC-V Processor
// FILE: RV32IM_SoC_Top.v
// DESCRIPTION: Top-Level ASIC Chip Envelope & Pin Mappings
// =================================================================

module RV32IM_SoC_Top (
    input  wire        pad_clk_p,
    input  wire        pad_clk_n,
    input  wire        pad_rst_n,

    // DDR Memory PHY Pins
    output wire [15:0] ddr_addr,
    inout  wire [31:0] ddr_dq,

    // Peripherals (UART, I2C, JTAG)
    input  wire        uart_rx,
    output wire        uart_tx,
    input  wire        jtag_tck,
    input  wire        jtag_tms,
    output wire        jtag_tdo
);

    // Differential Clock Buffers (ASIC Custom)
    wire sys_clk;
    IBUFDS clk_diff_buf (
        .I(pad_clk_p),
        .IB(pad_clk_n),
        .O(sys_clk)
    );

    // Quad Core Cluster Instance
    wire [127:0] axi_m_wdata;
    wire [31:0]  axi_m_addr;

    CPU_Cluster_4x cores_inst (
        .clk(sys_clk),
        .rst_n(pad_rst_n),
        .axi_addr(axi_m_addr),
        .axi_wdata(axi_m_wdata)
    );

    // Systolic NPU Core Accel
    NPU_Matrix_Engine npu_inst (
        .clk(sys_clk),
        .rst_n(pad_rst_n),
        .mem_addr(axi_m_addr)
    );

endmodule

// =================================================================
// PROJECT: UART Controller IP
// FILE: uart_tx.v
// DESCRIPTION: Parametric Transmitter Module with RTS/CTS
// =================================================================

module uart_tx #(
    parameter DATA_WIDTH = 8
)(
    input  wire                  clk,
    input  wire                  rst_n,
    input  wire                  tx_start,
    input  wire                  baud_tick,
    input  wire [DATA_WIDTH-1:0] tx_data,
    input  wire                  cts_n,
    output reg                   tx_out,
    output reg                   tx_busy,
    output reg                   tx_done
);

    typedef enum reg [1:0] {
        IDLE   = 2'b00,
        START  = 2'b01,
        DATA   = 2'b10,
        STOP   = 2'b11
    } state_t;

    state_t state, next_state;
    reg [2:0] bit_cnt;
    reg [DATA_WIDTH-1:0] tx_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state   <= IDLE;
            tx_out  <= 1'b1;
            tx_busy <= 1'b0;
            bit_cnt <= 3'b0;
        end else begin
            state <= next_state;
            if (state == IDLE && tx_start && !cts_n) begin
                tx_reg  <= tx_data;
                tx_busy <= 1'b1;
            end
        end
    end

endmodule

// =================================================================
// PROJECT: Cache Memory Controller
// FILE: cache_controller.v
// DESCRIPTION: 4-Way Set-Associative Cache Tag Compare Logic
// =================================================================

module cache_controller #(
    parameter TAG_WIDTH  = 20,
    parameter SET_WIDTH  = 6,
    parameter LINE_WIDTH = 512 // 64 Bytes
)(
    input  wire                  clk,
    input  wire                  rst_n,
    input  wire                  req_valid,
    input  wire [31:0]           req_addr,
    input  wire                  req_write,
    output reg                   req_ready,
    output reg                   hit,

    // Snooping Interface for Coherency
    input  wire [31:0]           snoop_addr,
    input  wire [1:0]            snoop_type,
    output reg  [1:0]            snoop_response
);

    // Cache Ways SRAM Arrays (Surgically pipelined for timing)
    wire [TAG_WIDTH-1:0] tag_way0, tag_way1, tag_way2, tag_way3;
    wire                 valid_way0, valid_way1, valid_way2, valid_way3;

    wire [TAG_WIDTH-1:0] target_tag = req_addr[31:12];
    wire [SET_WIDTH-1:0] target_set = req_addr[11:6];

    // Tag comparison matrix
    wire match0 = valid_way0 && (tag_way0 == target_tag);
    wire match1 = valid_way1 && (tag_way1 == target_tag);
    wire match2 = valid_way2 && (tag_way2 == target_tag);
    wire match3 = valid_way3 && (tag_way3 == target_tag);

    always @(*) begin
        hit = match0 || match1 || match2 || match3;
        req_ready = rst_n; // Ready unless locked on eviction line-fill
    end

endmodule

// =================================================================
// PROJECT: 8-Bit CPU
// FILE: alu_8bit.v
// DESCRIPTION: 8-Bit Arithmetic Logic Unit with flags output
// =================================================================

module alu_8bit (
    input  wire [7:0] a,
    input  wire [7:0] b,
    input  wire [2:0] op,
    output reg  [7:0] out,
    output wire       zero_flag,
    output wire       carry_flag
);

    reg [8:0] temp_sum;
    assign zero_flag = (out == 8'h00);
    assign carry_flag = temp_sum[8];

    always @(*) begin
        temp_sum = 9'h000;
        case (op)
            3'b000: begin temp_sum = {1'b0, a} + {1'b0, b}; out = temp_sum[7:0]; end // ADD
            3'b001: begin temp_sum = {1'b0, a} - {1'b0, b}; out = temp_sum[7:0]; end // SUB
            3'b010: out = a & b;          // AND
            3'b011: out = a | b;          // OR
            3'b100: out = a ^ b;          // XOR
            3'b101: out = a << 1;         // SHL
            3'b110: out = a >> 1;         // SHR
            3'b111: out = ~a;             // NOT
            default: out = 8'h00;
        endcase
    end

endmodule
